    "footer.privacy": "Datenschutzerklärung",
    "footer.more": "Weitere Tools",
    "footer.credit": "Erstellt von rayv",
    "meta.title": "Zeitzonen-Umrechner — eine Uhrzeit auf einmal in Großstädte umrechnen, mit automatischer Sommerzeit",
    "meta.description": "Kostenloser Online-Zeitzonen-Umrechner. Gib eine Uhrzeit ein und sieh sofort, wie spät es in New York, London, Tokio und mehr ist — mit UTC-Abständen, +1-Tag- / -1-Tag-Labels und automatischer Sommerzeit. Ohne Installation, ohne Anmeldung, werbefrei.",
    "hero.lede": "Wähle eine Uhrzeit und ein paar Städte. Die Abstände und die Sommerzeit übernehmen wir für dich.",
    "tool.baseTime": "Basiszeit",
    "tool.baseZone": "Basis-Zeitzone",
